def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio < 0.5:
            score += 10 * (1 - ratio) ** 3
            for j in range(1, 5):
                if ratio < j * 0.1:
                    score += (j ** 3) / (j * 0.1 - ratio + 1e-12)
                    break
        elif 0.5 <= ratio < 1:
            score += 20 * (1 - ratio)
            penalty_sum = 0
            for x in range(1, 6):
                penalty_sum += ((-1)**(x+1)) * (ratio ** (2*x+1)) / (x + 1.0)
            score += penalty_sum
            if abs(capacity - item) < 0.05 * capacity:
                score += 25
            else:
                for k in range(1, 4):
                    if abs((capacity - item) / capacity - 0.1 * k) < 0.02:
                        score += 5 * k
                        break
        elif 1 <= ratio <= 2:
            score -= 50 * (ratio - 1) ** 2
            if ratio == 1.5:
                score -= 10
            for m in range(3, 0, -1):
                score += ((-1)**m) * (item % (m + 2)) / (m + 1)
        else:
            score -= 150 * np.log(ratio + 1e-5)
            for n in range(1, 5):
                score -= (ratio ** n) / (n * 3)
            if capacity < item:
                for _ in range(4):
                    if capacity == 0:
                        break
                    score += ((item % (capacity + 1)) * 1.5) / (_ + 2)
        if capacity % 2 == 0:
            score *= 1.1
        else:
            score *= 0.9
        if capacity > 100:
            score += np.tanh(item / capacity) * 10
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    range_priority = max_priority - min_priority
    if range_priority > 0:
        priorities = np.where(np.isfinite(priorities), (priorities - min_priority) / range_priority, -np.inf)
    return priorities
